2	// matched_filter_multi_segment.v
3	module matched_filter_multi_segment (
4	    input wire clk,           // 100MHz
5	    input wire reset_n,
6	    
7	    // Input from DDC (100 MSPS)
8	    input wire signed [17:0] ddc_i,
9	    input wire signed [17:0] ddc_q,
10	    input wire ddc_valid,
11	    
12	    // Chirp control (from sequence controller)
13	    input wire use_long_chirp,      // 
14	    input wire [5:0] chirp_counter, // 
15	    
16	    // Microcontroller sync signals
17	    input wire mc_new_chirp,        // Toggle for new chirp (32)
18	    input wire mc_new_elevation,    // Toggle for new elevation (32)
19	    input wire mc_new_azimuth,      // Toggle for new azimuth (50)
20	    
21	    input wire [15:0] long_chirp_real,
22	    input wire [15:0] long_chirp_imag,
23	    input wire [15:0] short_chirp_real,
24	    input wire [15:0] short_chirp_imag,
25	    
26	    // Memory system interface
27	    output reg [1:0] segment_request,
28	    output wire [9:0] sample_addr_out,  // Tell memory which sample we need
29	    output reg mem_request,
30	    input wire mem_ready,
31	    
32	    // Output: Pulse compressed
33	    output wire signed [15:0] pc_i_w,
34	    output wire signed [15:0] pc_q_w,
35	    output wire pc_valid_w,
36	    
37	    // Status
38	    output reg [3:0] status
39	);
40	
41	// ========== FIXED PARAMETERS ==========
42	parameter BUFFER_SIZE = 1024;
43	parameter LONG_CHIRP_SAMPLES = 3000;  // Still 3000 samples total
44	parameter SHORT_CHIRP_SAMPLES = 50;   // 0.5�s @ 100MHz
45	parameter OVERLAP_SAMPLES = 128;      // Standard for 1024-pt FFT
46	parameter SEGMENT_ADVANCE = BUFFER_SIZE - OVERLAP_SAMPLES;  // 896 samples
47	parameter DEBUG = 1;                  // Debug output control
48	
49	// Calculate segments needed with overlap
50	// For 3072 samples with 128 overlap: 
51	// Segments = ceil((3072 - 128) / 896) = ceil(2944/896) = 4
52	parameter LONG_SEGMENTS = 4;          // Now exactly 4 segments!
53	parameter SHORT_SEGMENTS = 1;         // 50 samples padded to 1024
54	
55	// ========== FIXED INTERNAL SIGNALS ==========
56	reg signed [31:0] pc_i, pc_q;
57	reg pc_valid;
58	
59	// Dual buffer for overlap-save — BRAM inferred for synthesis
60	(* ram_style = "block" *) reg signed [15:0] input_buffer_i [0:BUFFER_SIZE-1];
61	(* ram_style = "block" *) reg signed [15:0] input_buffer_q [0:BUFFER_SIZE-1];
62	reg [10:0] buffer_write_ptr;
63	reg [10:0] buffer_read_ptr;
64	reg buffer_has_data;
65	reg buffer_processing;
66	reg [15:0] chirp_samples_collected;
67	
68	// BRAM write port signals
69	reg        buf_we;
70	reg [9:0]  buf_waddr;
71	reg signed [15:0] buf_wdata_i, buf_wdata_q;
72	
73	// BRAM read port signals
74	reg [9:0]  buf_raddr;
75	reg signed [15:0] buf_rdata_i, buf_rdata_q;
76	
77	// State machine
78	reg [3:0] state;
79	localparam ST_IDLE = 0;
80	localparam ST_COLLECT_DATA = 1;
81	localparam ST_ZERO_PAD = 2;
82	localparam ST_WAIT_REF = 3;
83	localparam ST_PROCESSING = 4;
84	localparam ST_WAIT_FFT = 5;
85	localparam ST_OUTPUT = 6;
86	localparam ST_NEXT_SEGMENT = 7;
87	localparam ST_OVERLAP_COPY = 8;
88	
89	// Segment tracking
90	reg [2:0] current_segment;        // 0-3
91	reg [2:0] total_segments;
92	reg segment_done;
93	reg chirp_complete;
94	reg saw_chain_output;             // Flag: chain started producing output
95	
96	// Overlap cache — captured during ST_PROCESSING, written back in ST_OVERLAP_COPY
97	reg signed [15:0] overlap_cache_i [0:OVERLAP_SAMPLES-1];
98	reg signed [15:0] overlap_cache_q [0:OVERLAP_SAMPLES-1];
99	reg [7:0] overlap_copy_count;
100	
101	// Microcontroller sync detection
102	reg mc_new_chirp_prev, mc_new_elevation_prev, mc_new_azimuth_prev;
103	wire chirp_start_pulse = mc_new_chirp && !mc_new_chirp_prev;
104	wire elevation_change_pulse = mc_new_elevation && !mc_new_elevation_prev;
105	wire azimuth_change_pulse = mc_new_azimuth && !mc_new_azimuth_prev;
106	
107	// Processing chain signals
108	wire [15:0] fft_pc_i, fft_pc_q;
109	wire fft_pc_valid;
110	wire [3:0] fft_chain_state;
111	
112	// Buffer for FFT input
113	reg [15:0] fft_input_i, fft_input_q;
114	reg fft_input_valid;
115	reg fft_start;
116	
117	// ========== SAMPLE ADDRESS OUTPUT ==========
118	assign sample_addr_out = buffer_read_ptr;
119	
120	// ========== MICROCONTROLLER SYNC ==========
121	always @(posedge clk or negedge reset_n) begin
122	    if (!reset_n) begin
123	        mc_new_chirp_prev <= 1'b0;
124	        mc_new_elevation_prev <= 1'b0;
125	        mc_new_azimuth_prev <= 1'b0;
126	    end else begin
127	        mc_new_chirp_prev <= mc_new_chirp;
128	        mc_new_elevation_prev <= mc_new_elevation;
129	        mc_new_azimuth_prev <= mc_new_azimuth;
130	    end
131	end
132	
133	// ========== BUFFER INITIALIZATION ==========
134	integer buf_init;
135	integer ov_init;
136	initial begin
137	    for (buf_init = 0; buf_init < BUFFER_SIZE; buf_init = buf_init + 1) begin
138	        input_buffer_i[buf_init] = 16'd0;
139	        input_buffer_q[buf_init] = 16'd0;
140	    end
141	    for (ov_init = 0; ov_init < OVERLAP_SAMPLES; ov_init = ov_init + 1) begin
142	        overlap_cache_i[ov_init] = 16'd0;
143	        overlap_cache_q[ov_init] = 16'd0;
144	    end
145	end
146	
147	// ========== BRAM WRITE PORT (synchronous, no async reset) ==========
148	always @(posedge clk) begin
149	    if (buf_we) begin
150	        input_buffer_i[buf_waddr] <= buf_wdata_i;
151	        input_buffer_q[buf_waddr] <= buf_wdata_q;
152	    end
153	end
154	
155	// ========== BRAM READ PORT (synchronous, no async reset) ==========
156	always @(posedge clk) begin
157	    buf_rdata_i <= input_buffer_i[buf_raddr];
158	    buf_rdata_q <= input_buffer_q[buf_raddr];
159	end
160	
161	// ========== FIXED STATE MACHINE WITH OVERLAP-SAVE ==========
162	integer i;
163	always @(posedge clk or negedge reset_n) begin
164	    if (!reset_n) begin
165	        state <= ST_IDLE;
166	        buffer_write_ptr <= 0;
167	        buffer_read_ptr <= 0;
168	        buffer_has_data <= 0;
169	        buffer_processing <= 0;
170	        current_segment <= 0;
171	        segment_done <= 0;
172	        segment_request <= 0;
173	        mem_request <= 0;
174	        pc_valid <= 0;
175	        status <= 0;
176	        chirp_samples_collected <= 0;
177	        chirp_complete <= 0;
178	        saw_chain_output <= 0;
179	        fft_input_valid <= 0;
180	        fft_start <= 0;
181	        buf_we <= 0;
182	        buf_waddr <= 0;
183	        buf_wdata_i <= 0;
184	        buf_wdata_q <= 0;
185	        buf_raddr <= 0;
186	        overlap_copy_count <= 0;
187	    end else begin
188	        pc_valid <= 0;
189	        mem_request <= 0;
190	        fft_input_valid <= 0;
191	        buf_we <= 0;  // Default: no write
192	        
193	        case (state)
194	            ST_IDLE: begin
195	                // Reset for new chirp
196	                buffer_write_ptr <= 0;
197	                buffer_read_ptr <= 0;
198	                buffer_has_data <= 0;
199	                buffer_processing <= 0;
200	                current_segment <= 0;
201	                segment_done <= 0;
202	                chirp_samples_collected <= 0;
203	                chirp_complete <= 0;
204	                saw_chain_output <= 0;
205	                
206	                // Wait for chirp start from microcontroller
207	                if (chirp_start_pulse) begin
208	                    state <= ST_COLLECT_DATA;
209	                    total_segments <= use_long_chirp ? LONG_SEGMENTS[2:0] : SHORT_SEGMENTS[2:0];
210	                    
211	                    `ifdef SIMULATION
212	                    $display("[MULTI_SEG_FIXED] Starting %s chirp, segments: %d",
213	                             use_long_chirp ? "LONG" : "SHORT", 
214	                             use_long_chirp ? LONG_SEGMENTS : SHORT_SEGMENTS);
215	                    $display("[MULTI_SEG_FIXED] Overlap: %d samples, Advance: %d samples",
216	                             OVERLAP_SAMPLES, SEGMENT_ADVANCE);
217	                    `endif
218	                end
219	            end
220	            
221	            ST_COLLECT_DATA: begin
222	                // Collect samples for current segment with overlap-save
223	                if (ddc_valid && buffer_write_ptr < BUFFER_SIZE) begin
224	                    // Store in buffer via BRAM write port
225	                    buf_we <= 1;
226	                    buf_waddr <= buffer_write_ptr[9:0];
227	                    buf_wdata_i <= ddc_i[17:2] + ddc_i[1];
228	                    buf_wdata_q <= ddc_q[17:2] + ddc_q[1];
229	                    
230	                    buffer_write_ptr <= buffer_write_ptr + 1;
231	                    chirp_samples_collected <= chirp_samples_collected + 1;
232	                    
233	                    // Debug: Show first few samples
234	                    if (chirp_samples_collected < 10 && buffer_write_ptr < 10) begin
235	                        `ifdef SIMULATION
236	                        $display("[MULTI_SEG_FIXED] Store[%0d]: I=%h Q=%h", 
237	                                 buffer_write_ptr, 
238	                                 ddc_i[17:2] + ddc_i[1], 
239	                                 ddc_q[17:2] + ddc_q[1]);
240	                        `endif
241	                    end
242	                    
243	                    // SHORT CHIRP: Only 50 samples, then zero-pad
244	                    if (!use_long_chirp) begin
245	                        if (chirp_samples_collected >= SHORT_CHIRP_SAMPLES - 1) begin
246	                            state <= ST_ZERO_PAD;
247	                            `ifdef SIMULATION
248	                            $display("[MULTI_SEG_FIXED] Short chirp: collected %d samples, starting zero-pad",
249	                                     chirp_samples_collected + 1);
250	                            `endif
251	                        end
252	                    end
253	                end
254	                
255	                // LONG CHIRP: segment-ready and chirp-complete checks
256	                // evaluated every clock (not gated by ddc_valid) to avoid
257	                // missing the transition when buffer_write_ptr updates via
258	                // non-blocking assignment one cycle after the last write.
259	                //
260	                // Overlap-save fix: fill the FULL 1024-sample buffer before
261	                // processing.  For segment 0 this means 1024 fresh samples.
262	                // For segments 1+, write_ptr starts at OVERLAP_SAMPLES (128)
263	                // so we collect 896 new samples to fill the buffer.
264	                if (use_long_chirp) begin
265	                    if (buffer_write_ptr >= BUFFER_SIZE) begin
266	                        buffer_has_data <= 1;
267	                        state <= ST_WAIT_REF;
268	                        segment_request <= current_segment[1:0];
269	                        mem_request <= 1;
270	                        
271	                        `ifdef SIMULATION
272	                        $display("[MULTI_SEG_FIXED] Segment %d ready: %d samples collected",
273	                                 current_segment, chirp_samples_collected);
274	                        `endif
275	                    end
276	                    
277	                    if (chirp_samples_collected >= LONG_CHIRP_SAMPLES && !chirp_complete) begin
278	                        chirp_complete <= 1;
279	                        `ifdef SIMULATION
280	                        $display("[MULTI_SEG_FIXED] End of long chirp reached");
281	                        `endif
282	                        // If buffer isn't full yet, zero-pad the remainder
283	                        // (last segment with fewer than 896 new samples)
284	                        if (buffer_write_ptr < BUFFER_SIZE) begin
285	                            state <= ST_ZERO_PAD;
286	                            `ifdef SIMULATION
287	                            $display("[MULTI_SEG_FIXED] Last segment partial: zero-padding from %0d to %0d",
288	                                     buffer_write_ptr, BUFFER_SIZE - 1);
289	                            `endif
290	                        end
291	                    end
292	                end
293	            end
294	            
295	            ST_ZERO_PAD: begin
296	                // Zero-pad remaining buffer via BRAM write port
297	                buf_we <= 1;
298	                buf_waddr <= buffer_write_ptr[9:0];
299	                buf_wdata_i <= 16'd0;
300	                buf_wdata_q <= 16'd0;
301	                buffer_write_ptr <= buffer_write_ptr + 1;
302	                
303	                if (buffer_write_ptr >= BUFFER_SIZE - 1) begin
304	                    // Done zero-padding
305	                    buffer_has_data <= 1;
306	                    buffer_write_ptr <= 0;
307	                    state <= ST_WAIT_REF;
308	                    segment_request <= use_long_chirp ? current_segment[1:0] : 2'd0;
309	                    mem_request <= 1;
310	                    `ifdef SIMULATION
311	                    $display("[MULTI_SEG_FIXED] Zero-pad complete, buffer full");
312	                    `endif
313	                end
314	            end
315	            
316	            ST_WAIT_REF: begin
317	                // Wait for memory to provide reference coefficients
318	                buf_raddr <= 10'd0;  // Pre-present addr 0 so buf_rdata is ready next cycle
319	                if (mem_ready) begin
320	                    // Start processing — buf_rdata[0] will be valid on FIRST clock of ST_PROCESSING
321	                    buffer_processing <= 1;
322	                    buffer_read_ptr <= 0;
323	                    fft_start <= 1;
324	                    state <= ST_PROCESSING;
325	                    
326	                    `ifdef SIMULATION
327	                    $display("[MULTI_SEG_FIXED] Reference ready, starting processing segment %d",
328	                             current_segment);
329	                    `endif
330	                end
331	            end
332	            
333	            ST_PROCESSING: begin
334	                // Feed data to FFT chain from BRAM.
335	                // buf_raddr was pre-presented in ST_WAIT_REF (=0), so
336	                // buf_rdata already contains data[0] on the first clock here.
337	                // Each cycle: feed buf_rdata, present NEXT address.
338	                if ((buffer_processing) && (buffer_read_ptr < BUFFER_SIZE)) begin
339	                    // 1. Feed BRAM read data to FFT (valid for current buffer_read_ptr)
340	                    fft_input_i <= buf_rdata_i;
341	                    fft_input_q <= buf_rdata_q;
342	                    fft_input_valid <= 1;
343	                    
344	                    // 2. Request corresponding reference sample
345	                    mem_request <= 1'b1;
346	                    
347	                    // 3. Cache tail samples for overlap-save
348	                    if (buffer_read_ptr >= SEGMENT_ADVANCE) begin
349	                        overlap_cache_i[buffer_read_ptr - SEGMENT_ADVANCE] <= buf_rdata_i;
350	                        overlap_cache_q[buffer_read_ptr - SEGMENT_ADVANCE] <= buf_rdata_q;
351	                    end
352	                    
353	                    // Debug every 100 samples
354	                    if (buffer_read_ptr % 100 == 0) begin
355	                        `ifdef SIMULATION
356	                        $display("[MULTI_SEG_FIXED] Processing[%0d]: ADC I=%h Q=%h",
357	                                buffer_read_ptr,
358	                                buf_rdata_i,
359	                                buf_rdata_q);
360	                        `endif
361	                    end
362	                    
363	                    // Present NEXT read address (for next cycle)
364	                    buf_raddr <= buffer_read_ptr[9:0] + 10'd1;
365	                    buffer_read_ptr <= buffer_read_ptr + 1;
366	                    
367	                end else if (buffer_read_ptr >= BUFFER_SIZE) begin
368	                    // Done feeding buffer
369	                    fft_input_valid <= 0;
370	                    mem_request <= 0;
371	                    buffer_processing <= 0;
372	                    buffer_has_data <= 0;
373	                    saw_chain_output <= 0;
374	                    state <= ST_WAIT_FFT;  // CRITICAL: Wait for FFT completion
375	                    
376	                    `ifdef SIMULATION
377	                    $display("[MULTI_SEG_FIXED] Finished feeding %d samples to FFT, waiting...",
378	                             BUFFER_SIZE);
379	                    `endif
380	                end
381	            end
382	            
383	            ST_WAIT_FFT: begin
384	                // Wait for the processing chain to complete ALL outputs.
385	                // The chain streams 1024 samples (fft_pc_valid=1 for 1024 clocks),
386	                // then transitions to ST_DONE (9) -> ST_IDLE (0).
387	                // We track when output starts (saw_chain_output) and only
388	                // proceed once the chain returns to idle after outputting.
389	                if (fft_pc_valid) begin
390	                    saw_chain_output <= 1;
391	                end
392	                
393	                if (saw_chain_output && fft_chain_state == 4'd0) begin
394	                    // Chain has returned to idle after completing all output
395	                    saw_chain_output <= 0;
396	                    state <= ST_OUTPUT;
397	                    `ifdef SIMULATION
398	                    $display("[MULTI_SEG_FIXED] Chain complete for segment %d, entering ST_OUTPUT",
399	                             current_segment);
400	                    `endif
401	                end
402	            end
403	            
404	            ST_OUTPUT: begin
405	                // Store FFT output
406	                pc_i <= fft_pc_i;
407	                pc_q <= fft_pc_q;
408	                pc_valid <= 1;
409	                segment_done <= 1;
410	                
411	                `ifdef SIMULATION
412	                $display("[MULTI_SEG_FIXED] Output segment %d: I=%h Q=%h",
413	                         current_segment, fft_pc_i, fft_pc_q);
414	                `endif
415	                
416	                // Check if we need more segments
417	                if (current_segment < total_segments - 1 || !chirp_complete) begin
418	                    state <= ST_NEXT_SEGMENT;
419	                end else begin
420	                    // All segments complete
421	                    state <= ST_IDLE;
422	                    `ifdef SIMULATION
423	                    $display("[MULTI_SEG_FIXED] All %d segments complete",
424	                             total_segments);
425	                    `endif
426	                end
427	            end
428	            
429	            ST_NEXT_SEGMENT: begin
430	                // Prepare for next segment with OVERLAP-SAVE
431	                current_segment <= current_segment + 1;
432	                segment_done <= 0;
433	                
434	                if (use_long_chirp) begin
435	                    // OVERLAP-SAVE: Write cached tail samples back to BRAM [0..127]
436	                    overlap_copy_count <= 0;
437	                    state <= ST_OVERLAP_COPY;
438	                    
439	                    `ifdef SIMULATION
440	                    $display("[MULTI_SEG_FIXED] Overlap-save: writing %d cached samples",
441	                             OVERLAP_SAMPLES);
442	                    `endif
443	                end else begin
444	                    // Short chirp: only one segment
445	                    buffer_write_ptr <= 0;
446	                    if (!chirp_complete) begin
447	                        state <= ST_COLLECT_DATA;
448	                    end else begin
449	                        state <= ST_IDLE;
450	                    end
451	                end
452	            end
453	            
454	            ST_OVERLAP_COPY: begin
455	                // Write one cached overlap sample per cycle to BRAM
456	                buf_we <= 1;
457	                buf_waddr <= {{2{1'b0}}, overlap_copy_count};
458	                buf_wdata_i <= overlap_cache_i[overlap_copy_count];
459	                buf_wdata_q <= overlap_cache_q[overlap_copy_count];
460	                
461	                if (overlap_copy_count < OVERLAP_SAMPLES - 1) begin
462	                    overlap_copy_count <= overlap_copy_count + 1;
463	                end else begin
464	                    // All 128 samples written back
465	                    buffer_write_ptr <= OVERLAP_SAMPLES;
466	                    
467	                    `ifdef SIMULATION
468	                    $display("[MULTI_SEG_FIXED] Overlap-save: copied %d samples, write_ptr=%d",
469	                             OVERLAP_SAMPLES, OVERLAP_SAMPLES);
470	                    `endif
471	                    
472	                    if (!chirp_complete) begin
473	                        state <= ST_COLLECT_DATA;
474	                    end else begin
475	                        state <= ST_IDLE;
476	                    end
477	                end
478	            end
479	            
480	            default: begin
481	                state <= ST_IDLE;
482	            end
483	        endcase
484	        
485	        // Update status
486	        status <= {state[2:0], use_long_chirp};
487	    end
488	end
489	
490	// ========== PROCESSING CHAIN INSTANTIATION ==========
491	matched_filter_processing_chain m_f_p_c(
492	    .clk(clk),
493	    .reset_n(reset_n),
494	    
495	    // Input ADC Data
496	    .adc_data_i(fft_input_i),
497	    .adc_data_q(fft_input_q),
498	    .adc_valid(fft_input_valid),// && buffer_processing),
499	    
500	    // Chirp Selection
501	    .chirp_counter(chirp_counter),
502	    
503	    // Reference Chirp Memory Interfaces
504	    .long_chirp_real(long_chirp_real),
505	    .long_chirp_imag(long_chirp_imag),
506	    .short_chirp_real(short_chirp_real),
507	    .short_chirp_imag(short_chirp_imag),
508	    
509	    // Output
510	    .range_profile_i(fft_pc_i),
511	    .range_profile_q(fft_pc_q),
512	    .range_profile_valid(fft_pc_valid),
513	    
514	    // Status
515	    .chain_state(fft_chain_state)
516	);
517	
518	// ========== DEBUG MONITOR ==========
519	`ifdef SIMULATION
520	reg [31:0] dbg_cycles;
521	always @(posedge clk or negedge reset_n) begin
522	    if (!reset_n) begin
523	        dbg_cycles <= 0;
524	    end else begin
525	        dbg_cycles <= dbg_cycles + 1;
526	        
527	        // Monitor state transitions
528	        if (dbg_cycles % 1000 == 0 && state != ST_IDLE) begin
529	            $display("[MULTI_SEG_MONITOR @%0d] state=%0d, segment=%0d/%0d, samples=%0d",
530	                     dbg_cycles, state, current_segment, total_segments,
531	                     chirp_samples_collected);
532	        end
533	    end
534	end
535	`endif
536	
537	// ========== OUTPUT CONNECTIONS ==========
538	assign pc_i_w = fft_pc_i;
539	assign pc_q_w = fft_pc_q;
540	assign pc_valid_w = fft_pc_valid;
541	
542	endmodule

