`timescale 1ns / 1ps
// matched_filter_multi_segment.v
module matched_filter_multi_segment (
    input wire clk,           // 100MHz
    input wire reset_n,

    // Input from DDC (100 MSPS)
    input wire signed [17:0] ddc_i,
    input wire signed [17:0] ddc_q,
    input wire ddc_valid,

    // Chirp control (from sequence controller)
    input wire use_long_chirp,      // 
    input wire [5:0] chirp_counter, // 

    // Microcontroller sync signals
    input wire mc_new_chirp,        // Toggle for new chirp (32)
    input wire mc_new_elevation,    // Toggle for new elevation (32)
    input wire mc_new_azimuth,      // Toggle for new azimuth (50)

    input wire [15:0] long_chirp_real,
    input wire [15:0] long_chirp_imag,
    input wire [15:0] short_chirp_real,
    input wire [15:0] short_chirp_imag,

    // Memory system interface
    output reg [1:0] segment_request,
    output wire [9:0] sample_addr_out,  // Tell memory which sample we need
    output reg mem_request,
    input wire mem_ready,

    // Output: Pulse compressed
    output wire signed [15:0] pc_i_w,
    output wire signed [15:0] pc_q_w,
    output wire pc_valid_w,

    // Status
    output reg [3:0] status
);

// ========== FIXED PARAMETERS ==========
parameter BUFFER_SIZE = 1024;
parameter LONG_CHIRP_SAMPLES = 3000;  // Still 3000 samples total
parameter SHORT_CHIRP_SAMPLES = 50;   // 0.5�s @ 100MHz
parameter OVERLAP_SAMPLES = 128;      // Standard for 1024-pt FFT
parameter SEGMENT_ADVANCE = BUFFER_SIZE - OVERLAP_SAMPLES;  // 896 samples
parameter DEBUG = 1;                  // Debug output control

// Calculate segments needed with overlap
// For 3072 samples with 128 overlap: 
// Segments = ceil((3072 - 128) / 896) = ceil(2944/896) = 4
parameter LONG_SEGMENTS = 4;          // Now exactly 4 segments!
parameter SHORT_SEGMENTS = 1;         // 50 samples padded to 1024

// ========== FIXED INTERNAL SIGNALS ==========
reg signed [31:0] pc_i, pc_q;
reg pc_valid;

// Dual buffer for overlap-save — BRAM inferred for synthesis
(* ram_style = "block" *) reg signed [15:0] input_buffer_i [0:BUFFER_SIZE-1];
(* ram_style = "block" *) reg signed [15:0] input_buffer_q [0:BUFFER_SIZE-1];
reg [10:0] buffer_write_ptr;
reg [10:0] buffer_read_ptr;
reg buffer_has_data;
reg buffer_processing;
reg [15:0] chirp_samples_collected;

// BRAM write port signals
reg        buf_we;
reg [9:0]  buf_waddr;
reg signed [15:0] buf_wdata_i, buf_wdata_q;

// BRAM read port signals
reg [9:0]  buf_raddr;
reg signed [15:0] buf_rdata_i, buf_rdata_q;

// State machine
reg [3:0] state;
localparam ST_IDLE = 0;
localparam ST_COLLECT_DATA = 1;
localparam ST_ZERO_PAD = 2;
localparam ST_WAIT_REF = 3;
localparam ST_PROCESSING = 4;
localparam ST_WAIT_FFT = 5;
localparam ST_OUTPUT = 6;
localparam ST_NEXT_SEGMENT = 7;
localparam ST_OVERLAP_COPY = 8;

// Segment tracking
reg [2:0] current_segment;        // 0-3
reg [2:0] total_segments;
reg segment_done;
reg chirp_complete;
reg saw_chain_output;             // Flag: chain started producing output

// Overlap cache — captured during ST_PROCESSING, written back in ST_OVERLAP_COPY
reg signed [15:0] overlap_cache_i [0:OVERLAP_SAMPLES-1];
reg signed [15:0] overlap_cache_q [0:OVERLAP_SAMPLES-1];
reg [7:0] overlap_copy_count;

// Microcontroller sync detection
reg mc_new_chirp_prev, mc_new_elevation_prev, mc_new_azimuth_prev;
wire chirp_start_pulse = mc_new_chirp && !mc_new_chirp_prev;
wire elevation_change_pulse = mc_new_elevation && !mc_new_elevation_prev;
wire azimuth_change_pulse = mc_new_azimuth && !mc_new_azimuth_prev;

// Processing chain signals
wire [15:0] fft_pc_i, fft_pc_q;
wire fft_pc_valid;
wire [3:0] fft_chain_state;

// Buffer for FFT input
reg [15:0] fft_input_i, fft_input_q;
reg fft_input_valid;
reg fft_start;

// ========== SAMPLE ADDRESS OUTPUT ==========
assign sample_addr_out = buffer_read_ptr;

// ========== MICROCONTROLLER SYNC ==========
always @(posedge clk or negedge reset_n) begin
    if (!reset_n) begin
        mc_new_chirp_prev <= 1'b0;
        mc_new_elevation_prev <= 1'b0;
        mc_new_azimuth_prev <= 1'b0;
    end else begin
        mc_new_chirp_prev <= mc_new_chirp;
        mc_new_elevation_prev <= mc_new_elevation;
        mc_new_azimuth_prev <= mc_new_azimuth;
    end
end

// ========== BUFFER INITIALIZATION ==========
integer buf_init;
integer ov_init;
initial begin
    for (buf_init = 0; buf_init < BUFFER_SIZE; buf_init = buf_init + 1) begin
        input_buffer_i[buf_init] = 16'd0;
        input_buffer_q[buf_init] = 16'd0;
    end
    for (ov_init = 0; ov_init < OVERLAP_SAMPLES; ov_init = ov_init + 1) begin
        overlap_cache_i[ov_init] = 16'd0;
        overlap_cache_q[ov_init] = 16'd0;
    end
end

// ========== BRAM WRITE PORT (synchronous, no async reset) ==========
always @(posedge clk) begin
    if (buf_we) begin
        input_buffer_i[buf_waddr] <= buf_wdata_i;
        input_buffer_q[buf_waddr] <= buf_wdata_q;
    end
end

// ========== BRAM READ PORT (synchronous, no async reset) ==========
always @(posedge clk) begin
    buf_rdata_i <= input_buffer_i[buf_raddr];
    buf_rdata_q <= input_buffer_q[buf_raddr];
end

// ========== FIXED STATE MACHINE WITH OVERLAP-SAVE ==========
integer i;
always @(posedge clk or negedge reset_n) begin
    if (!reset_n) begin
        state <= ST_IDLE;
        buffer_write_ptr <= 0;
        buffer_read_ptr <= 0;
        buffer_has_data <= 0;
        buffer_processing <= 0;
        current_segment <= 0;
        segment_done <= 0;
        segment_request <= 0;
        mem_request <= 0;
        pc_valid <= 0;
        status <= 0;
        chirp_samples_collected <= 0;
        chirp_complete <= 0;
        saw_chain_output <= 0;
        fft_input_valid <= 0;
        fft_start <= 0;
        buf_we <= 0;
        buf_waddr <= 0;
        buf_wdata_i <= 0;
        buf_wdata_q <= 0;
        buf_raddr <= 0;
        overlap_copy_count <= 0;
    end else begin
        pc_valid <= 0;
        mem_request <= 0;
        fft_input_valid <= 0;
        buf_we <= 0;  // Default: no write

        case (state)
            ST_IDLE: begin
                // Reset for new chirp
                buffer_write_ptr <= 0;
                buffer_read_ptr <= 0;
                buffer_has_data <= 0;
                buffer_processing <= 0;
                current_segment <= 0;
                segment_done <= 0;
                chirp_samples_collected <= 0;
                chirp_complete <= 0;
                saw_chain_output <= 0;

                // Wait for chirp start from microcontroller
                if (chirp_start_pulse) begin
                    state <= ST_COLLECT_DATA;
                    total_segments <= use_long_chirp ? LONG_SEGMENTS[2:0] : SHORT_SEGMENTS[2:0];

                    `ifdef SIMULATION
                    $display("[MULTI_SEG_FIXED] Starting %s chirp, segments: %d",
                             use_long_chirp ? "LONG" : "SHORT", 
                             use_long_chirp ? LONG_SEGMENTS : SHORT_SEGMENTS);
                    $display("[MULTI_SEG_FIXED] Overlap: %d samples, Advance: %d samples",
                             OVERLAP_SAMPLES, SEGMENT_ADVANCE);
                    `endif
                end
            end

            ST_COLLECT_DATA: begin
                // Collect samples for current segment with overlap-save
                if (ddc_valid && buffer_write_ptr < BUFFER_SIZE) begin
                    // Store in buffer via BRAM write port
                    buf_we <= 1;
                    buf_waddr <= buffer_write_ptr[9:0];
                    buf_wdata_i <= ddc_i[17:2] + ddc_i[1];
                    buf_wdata_q <= ddc_q[17:2] + ddc_q[1];

                    buffer_write_ptr <= buffer_write_ptr + 1;
                    chirp_samples_collected <= chirp_samples_collected + 1;

                    // Debug: Show first few samples
                    if (chirp_samples_collected < 10 && buffer_write_ptr < 10) begin
                        `ifdef SIMULATION
                        $display("[MULTI_SEG_FIXED] Store[%0d]: I=%h Q=%h", 
                                 buffer_write_ptr, 
                                 ddc_i[17:2] + ddc_i[1], 
                                 ddc_q[17:2] + ddc_q[1]);
                        `endif
                    end

                    // SHORT CHIRP: Only 50 samples, then zero-pad
                    if (!use_long_chirp) begin
                        if (chirp_samples_collected >= SHORT_CHIRP_SAMPLES - 1) begin
                            state <= ST_ZERO_PAD;
                            `ifdef SIMULATION
                            $display("[MULTI_SEG_FIXED] Short chirp: collected %d samples, starting zero-pad",
                                     chirp_samples_collected + 1);
                            `endif
                        end
                    end
                end

                // LONG CHIRP: segment-ready and chirp-complete checks
                // evaluated every clock (not gated by ddc_valid) to avoid
                // missing the transition when buffer_write_ptr updates via
                // non-blocking assignment one cycle after the last write.
                //
                // Overlap-save fix: fill the FULL 1024-sample buffer before
                // processing.  For segment 0 this means 1024 fresh samples.
                // For segments 1+, write_ptr starts at OVERLAP_SAMPLES (128)
                // so we collect 896 new samples to fill the buffer.
                if (use_long_chirp) begin
                    if (buffer_write_ptr >= BUFFER_SIZE) begin
                        buffer_has_data <= 1;
                        state <= ST_WAIT_REF;
                        segment_request <= current_segment[1:0];
                        mem_request <= 1;

                        `ifdef SIMULATION
                        $display("[MULTI_SEG_FIXED] Segment %d ready: %d samples collected",
                                 current_segment, chirp_samples_collected);
                        `endif
                    end

                    if (chirp_samples_collected >= LONG_CHIRP_SAMPLES && !chirp_complete) begin
                        chirp_complete <= 1;
                        `ifdef SIMULATION
                        $display("[MULTI_SEG_FIXED] End of long chirp reached");
                        `endif
                        // If buffer isn't full yet, zero-pad the remainder
                        // (last segment with fewer than 896 new samples)
                        if (buffer_write_ptr < BUFFER_SIZE) begin
                            state <= ST_ZERO_PAD;
                            `ifdef SIMULATION
                            $display("[MULTI_SEG_FIXED] Last segment partial: zero-padding from %0d to %0d",
                                     buffer_write_ptr, BUFFER_SIZE - 1);
                            `endif
                        end
                    end
                end
            end

            ST_ZERO_PAD: begin
                // Zero-pad remaining buffer via BRAM write port
                buf_we <= 1;
                buf_waddr <= buffer_write_ptr[9:0];
                buf_wdata_i <= 16'd0;
                buf_wdata_q <= 16'd0;
                buffer_write_ptr <= buffer_write_ptr + 1;

                if (buffer_write_ptr >= BUFFER_SIZE - 1) begin
                    // Done zero-padding
                    buffer_has_data <= 1;
                    buffer_write_ptr <= 0;
                    state <= ST_WAIT_REF;
                    segment_request <= use_long_chirp ? current_segment[1:0] : 2'd0;
                    mem_request <= 1;
                    `ifdef SIMULATION
                    $display("[MULTI_SEG_FIXED] Zero-pad complete, buffer full");
                    `endif
                end
            end

            ST_WAIT_REF: begin
                // Wait for memory to provide reference coefficients
                buf_raddr <= 10'd0;  // Pre-present addr 0 so buf_rdata is ready next cycle
                if (mem_ready) begin
                    // Start processing — buf_rdata[0] will be valid on FIRST clock of ST_PROCESSING
                    buffer_processing <= 1;
                    buffer_read_ptr <= 0;
                    fft_start <= 1;
                    state <= ST_PROCESSING;

                    `ifdef SIMULATION
                    $display("[MULTI_SEG_FIXED] Reference ready, starting processing segment %d",
                             current_segment);
                    `endif
                end
            end

            ST_PROCESSING: begin
                // Feed data to FFT chain from BRAM.
                // buf_raddr was pre-presented in ST_WAIT_REF (=0), so
                // buf_rdata already contains data[0] on the first clock here.
                // Each cycle: feed buf_rdata, present NEXT address.
                if ((buffer_processing) && (buffer_read_ptr < BUFFER_SIZE)) begin
                    // 1. Feed BRAM read data to FFT (valid for current buffer_read_ptr)
                    fft_input_i <= buf_rdata_i;
                    fft_input_q <= buf_rdata_q;
                    fft_input_valid <= 1;

                    // 2. Request corresponding reference sample
                    mem_request <= 1'b1;

                    // 3. Cache tail samples for overlap-save
                    if (buffer_read_ptr >= SEGMENT_ADVANCE) begin
                        overlap_cache_i[buffer_read_ptr - SEGMENT_ADVANCE] <= buf_rdata_i;
                        overlap_cache_q[buffer_read_ptr - SEGMENT_ADVANCE] <= buf_rdata_q;
                    end

                    // Debug every 100 samples
                    if (buffer_read_ptr % 100 == 0) begin
                        `ifdef SIMULATION
                        $display("[MULTI_SEG_FIXED] Processing[%0d]: ADC I=%h Q=%h",
                                buffer_read_ptr,
                                buf_rdata_i,
                                buf_rdata_q);
                        `endif
                    end

                    // Present NEXT read address (for next cycle)
                    buf_raddr <= buffer_read_ptr[9:0] + 10'd1;
                    buffer_read_ptr <= buffer_read_ptr + 1;

                end else if (buffer_read_ptr >= BUFFER_SIZE) begin
                    // Done feeding buffer
                    fft_input_valid <= 0;
                    mem_request <= 0;
                    buffer_processing <= 0;
                    buffer_has_data <= 0;
                    saw_chain_output <= 0;
                    state <= ST_WAIT_FFT;  // CRITICAL: Wait for FFT completion

                    `ifdef SIMULATION
                    $display("[MULTI_SEG_FIXED] Finished feeding %d samples to FFT, waiting...",
                             BUFFER_SIZE);
                    `endif
                end
            end

            ST_WAIT_FFT: begin
                // Wait for the processing chain to complete ALL outputs.
                // The chain streams 1024 samples (fft_pc_valid=1 for 1024 clocks),
                // then transitions to ST_DONE (9) -> ST_IDLE (0).
                // We track when output starts (saw_chain_output) and only
                // proceed once the chain returns to idle after outputting.
                if (fft_pc_valid) begin
                    saw_chain_output <= 1;
                end

                if (saw_chain_output && fft_chain_state == 4'd0) begin
                    // Chain has returned to idle after completing all output
                    saw_chain_output <= 0;
                    state <= ST_OUTPUT;
                    `ifdef SIMULATION
                    $display("[MULTI_SEG_FIXED] Chain complete for segment %d, entering ST_OUTPUT",
                             current_segment);
                    `endif
                end
            end

            ST_OUTPUT: begin
                // Store FFT output
                pc_i <= fft_pc_i;
                pc_q <= fft_pc_q;
                pc_valid <= 1;
                segment_done <= 1;

                `ifdef SIMULATION
                $display("[MULTI_SEG_FIXED] Output segment %d: I=%h Q=%h",
                         current_segment, fft_pc_i, fft_pc_q);
                `endif

                // Check if we need more segments
                if (current_segment < total_segments - 1 || !chirp_complete) begin
                    state <= ST_NEXT_SEGMENT;
                end else begin
                    // All segments complete
                    state <= ST_IDLE;
                    `ifdef SIMULATION
                    $display("[MULTI_SEG_FIXED] All %d segments complete",
                             total_segments);
                    `endif
                end
            end

            ST_NEXT_SEGMENT: begin
                // Prepare for next segment with OVERLAP-SAVE
                current_segment <= current_segment + 1;
                segment_done <= 0;

                if (use_long_chirp) begin
                    // OVERLAP-SAVE: Write cached tail samples back to BRAM [0..127]
                    overlap_copy_count <= 0;
                    state <= ST_OVERLAP_COPY;

                    `ifdef SIMULATION
                    $display("[MULTI_SEG_FIXED] Overlap-save: writing %d cached samples",
                             OVERLAP_SAMPLES);
                    `endif
                end else begin
                    // Short chirp: only one segment
                    buffer_write_ptr <= 0;
                    if (!chirp_complete) begin
                        state <= ST_COLLECT_DATA;
                    end else begin
                        state <= ST_IDLE;
                    end
                end
            end

            ST_OVERLAP_COPY: begin
                // Write one cached overlap sample per cycle to BRAM
                buf_we <= 1;
                buf_waddr <= {{2{1'b0}}, overlap_copy_count};
                buf_wdata_i <= overlap_cache_i[overlap_copy_count];
                buf_wdata_q <= overlap_cache_q[overlap_copy_count];

                if (overlap_copy_count < OVERLAP_SAMPLES - 1) begin
                    overlap_copy_count <= overlap_copy_count + 1;
                end else begin
                    // All 128 samples written back
                    buffer_write_ptr <= OVERLAP_SAMPLES;

                    `ifdef SIMULATION
                    $display("[MULTI_SEG_FIXED] Overlap-save: copied %d samples, write_ptr=%d",
                             OVERLAP_SAMPLES, OVERLAP_SAMPLES);
                    `endif

                    if (!chirp_complete) begin
                        state <= ST_COLLECT_DATA;
                    end else begin
                        state <= ST_IDLE;
                    end
                end
            end

            default: begin
                state <= ST_IDLE;
            end
        endcase

        // Update status
        status <= {state[2:0], use_long_chirp};
    end
end

// ========== PROCESSING CHAIN INSTANTIATION ==========
matched_filter_processing_chain m_f_p_c(
    .clk(clk),
    .reset_n(reset_n),

    // Input ADC Data
    .adc_data_i(fft_input_i),
    .adc_data_q(fft_input_q),
    .adc_valid(fft_input_valid),// && buffer_processing),

    // Chirp Selection
    .chirp_counter(chirp_counter),

    // Reference Chirp Memory Interfaces
    .long_chirp_real(long_chirp_real),
    .long_chirp_imag(long_chirp_imag),
    .short_chirp_real(short_chirp_real),
    .short_chirp_imag(short_chirp_imag),

    // Output
    .range_profile_i(fft_pc_i),
    .range_profile_q(fft_pc_q),
    .range_profile_valid(fft_pc_valid),

    // Status
    .chain_state(fft_chain_state)
);

// ========== DEBUG MONITOR ==========
`ifdef SIMULATION
reg [31:0] dbg_cycles;
always @(posedge clk or negedge reset_n) begin
    if (!reset_n) begin
        dbg_cycles <= 0;
    end else begin
        dbg_cycles <= dbg_cycles + 1;

        // Monitor state transitions
        if (dbg_cycles % 1000 == 0 && state != ST_IDLE) begin
            $display("[MULTI_SEG_MONITOR @%0d] state=%0d, segment=%0d/%0d, samples=%0d",
                     dbg_cycles, state, current_segment, total_segments,
                     chirp_samples_collected);
        end
    end
end
`endif

// ========== OUTPUT CONNECTIONS ==========
assign pc_i_w = fft_pc_i;
assign pc_q_w = fft_pc_q;
assign pc_valid_w = fft_pc_valid;

endmodule

content.content:
1	`timescale 1ns / 1ps
2	
3	/**
4	 * matched_filter_processing_chain.v
5	 *
6	 * Pulse compression processing chain for AERIS-10 FMCW radar.
7	 * Implements: FFT(signal) → FFT(reference) → Conjugate multiply → IFFT
8	 *
9	 * This is a SIMULATION-COMPATIBLE implementation that replaces the Xilinx
10	 * FFT IP cores (FFT_enhanced) with behavioral Radix-2 DIT FFT engines.
11	 * For synthesis, replace the behavioral FFT instances with the actual
12	 * Xilinx xfft IP blocks.
13	 *
14	 * Interface contract (from matched_filter_multi_segment.v line 361):
15	 *   .clk, .reset_n
16	 *   .adc_data_i, .adc_data_q, .adc_valid      <- from input buffer
17	 *   .chirp_counter                              <- 6-bit frame counter
18	 *   .long_chirp_real/imag, .short_chirp_real/imag <- reference (time-domain)
19	 *   .range_profile_i, .range_profile_q, .range_profile_valid -> output
20	 *   .chain_state                                -> 4-bit status
21	 *
22	 * Clock domain: clk (100 MHz system clock)
23	 * Data format:  16-bit signed (Q15 fixed-point)
24	 * FFT size:     1024 points
25	 *
26	 * Pipeline states:
27	 *   IDLE -> FWD_FFT (collect 1024 samples + bit-reverse copy)
28	 *        -> FWD_BUTTERFLY (forward FFT of signal)
29	 *        -> REF_BITREV (bit-reverse copy reference into work arrays)
30	 *        -> REF_BUTTERFLY (forward FFT of reference)
31	 *        -> MULTIPLY (conjugate multiply in freq domain)
32	 *        -> INV_BITREV (bit-reverse copy product)
33	 *        -> INV_BUTTERFLY (inverse FFT + 1/N scaling)
34	 *        -> OUTPUT (stream 1024 samples)
35	 *        -> DONE -> IDLE
36	 */
37	
38	module matched_filter_processing_chain (
39	    input wire clk,
40	    input wire reset_n,
41	
42	    // Input ADC data (from matched_filter_multi_segment buffer)
43	    input wire [15:0] adc_data_i,
44	    input wire [15:0] adc_data_q,
45	    input wire adc_valid,
46	
47	    // Chirp counter (for future multi-chirp modes)
48	    input wire [5:0] chirp_counter,
49	
50	    // Reference chirp (time-domain, latency-aligned by upstream buffer)
51	    input wire [15:0] long_chirp_real,
52	    input wire [15:0] long_chirp_imag,
53	    input wire [15:0] short_chirp_real,
54	    input wire [15:0] short_chirp_imag,
55	
56	    // Output: range profile (pulse-compressed)
57	    output wire signed [15:0] range_profile_i,
58	    output wire signed [15:0] range_profile_q,
59	    output wire range_profile_valid,
60	
61	    // Status
62	    output wire [3:0] chain_state
63	);
64	
65	`ifdef SIMULATION
66	// ============================================================================
67	// PARAMETERS
68	// ============================================================================
69	localparam FFT_SIZE   = 1024;
70	localparam ADDR_BITS  = 10;    // log2(1024)
71	
72	// State encoding (4-bit, up to 16 states)
73	localparam [3:0] ST_IDLE           = 4'd0;
74	localparam [3:0] ST_FWD_FFT        = 4'd1;   // Collect samples + bit-reverse
75	localparam [3:0] ST_FWD_BUTTERFLY  = 4'd2;   // Signal FFT butterflies
76	localparam [3:0] ST_REF_BITREV     = 4'd3;   // Bit-reverse copy reference
77	localparam [3:0] ST_REF_BUTTERFLY  = 4'd4;   // Reference FFT butterflies
78	localparam [3:0] ST_MULTIPLY       = 4'd5;   // Conjugate multiply
79	localparam [3:0] ST_INV_BITREV     = 4'd6;   // Bit-reverse copy product
80	localparam [3:0] ST_INV_BUTTERFLY  = 4'd7;   // IFFT butterflies + scale
81	localparam [3:0] ST_OUTPUT         = 4'd8;   // Stream results
82	localparam [3:0] ST_DONE           = 4'd9;   // Return to idle
83	
84	reg [3:0] state;
85	
86	// ============================================================================
87	// SIGNAL BUFFERS
88	// ============================================================================
89	// Input sample counter
90	reg [ADDR_BITS:0] fwd_in_count;     // 0..1024
91	reg fwd_frame_done;                  // All 1024 samples received
92	
93	// Signal time-domain buffer
94	reg signed [15:0] fwd_buf_i [0:FFT_SIZE-1];
95	reg signed [15:0] fwd_buf_q [0:FFT_SIZE-1];
96	
97	// Signal FFT output (frequency domain)
98	reg signed [15:0] fwd_out_i [0:FFT_SIZE-1];
99	reg signed [15:0] fwd_out_q [0:FFT_SIZE-1];
100	reg fwd_out_valid;
101	
102	// Reference time-domain buffer
103	reg signed [15:0] ref_buf_i [0:FFT_SIZE-1];
104	reg signed [15:0] ref_buf_q [0:FFT_SIZE-1];
105	
106	// Reference FFT output (frequency domain)
107	reg signed [15:0] ref_fft_i [0:FFT_SIZE-1];
108	reg signed [15:0] ref_fft_q [0:FFT_SIZE-1];
109	
110	// ============================================================================
111	// CONJUGATE MULTIPLY OUTPUT
112	// ============================================================================
113	reg signed [15:0] mult_out_i [0:FFT_SIZE-1];
114	reg signed [15:0] mult_out_q [0:FFT_SIZE-1];
115	reg mult_done;
116	
117	// ============================================================================
118	// INVERSE FFT OUTPUT
119	// ============================================================================
120	reg signed [15:0] ifft_out_i [0:FFT_SIZE-1];
121	reg signed [15:0] ifft_out_q [0:FFT_SIZE-1];
122	reg ifft_done;
123	
124	// Output streaming
125	reg [ADDR_BITS:0] out_count;
126	reg out_valid_reg;
127	reg signed [15:0] out_i_reg, out_q_reg;
128	
129	// ============================================================================
130	// BEHAVIORAL RADIX-2 DIT FFT (simulation only)
131	// ============================================================================
132	// Working arrays for FFT computation (shared between fwd, ref, and inv FFTs)
133	reg signed [31:0] work_re [0:FFT_SIZE-1];
134	reg signed [31:0] work_im [0:FFT_SIZE-1];
135	
136	// Bit-reverse function
137	function [ADDR_BITS-1:0] bit_reverse;
138	    input [ADDR_BITS-1:0] val;
139	    integer b;
140	    begin
141	        bit_reverse = 0;
142	        for (b = 0; b < ADDR_BITS; b = b + 1)
143	            bit_reverse[ADDR_BITS-1-b] = val[b];
144	    end
145	endfunction
146	
147	// FFT computation variables
148	integer fft_stage, fft_k, fft_j, fft_half, fft_span;
149	integer fft_idx_even, fft_idx_odd;
150	reg signed [31:0] tw_re, tw_im;
151	reg signed [31:0] t_re, t_im;
152	reg signed [31:0] u_re, u_im;
153	real tw_angle;
154	
155	// ============================================================================
156	// MAIN STATE MACHINE
157	// ============================================================================
158	integer i;
159	
160	always @(posedge clk or negedge reset_n) begin
161	    if (!reset_n) begin
162	        state          <= ST_IDLE;
163	        fwd_in_count   <= 0;
164	        fwd_frame_done <= 0;
165	        fwd_out_valid  <= 0;
166	        mult_done      <= 0;
167	        ifft_done      <= 0;
168	        out_count      <= 0;
169	        out_valid_reg  <= 0;
170	        out_i_reg      <= 16'd0;
171	        out_q_reg      <= 16'd0;
172	    end else begin
173	        // Defaults
174	        out_valid_reg <= 1'b0;
175	
176	        case (state)
177	        // ================================================================
178	        // IDLE: Wait for valid ADC data, start collecting 1024 samples
179	        // ================================================================
180	        ST_IDLE: begin
181	            fwd_in_count   <= 0;
182	            fwd_frame_done <= 0;
183	            fwd_out_valid  <= 0;
184	            mult_done      <= 0;
185	            ifft_done      <= 0;
186	            out_count      <= 0;
187	
188	            if (adc_valid) begin
189	                // Store first sample (signal + reference)
190	                fwd_buf_i[0] <= $signed(adc_data_i);
191	                fwd_buf_q[0] <= $signed(adc_data_q);
192	                ref_buf_i[0] <= $signed(long_chirp_real);
193	                ref_buf_q[0] <= $signed(long_chirp_imag);
194	                fwd_in_count <= 1;
195	                state        <= ST_FWD_FFT;
196	            end
197	        end
198	
199	        // ================================================================
200	        // FWD_FFT: Collect remaining samples, then bit-reverse copy signal
201	        // ================================================================
202	        ST_FWD_FFT: begin
203	            if (!fwd_frame_done) begin
204	                // Still collecting samples
205	                if (adc_valid && fwd_in_count < FFT_SIZE) begin
206	                    fwd_buf_i[fwd_in_count] <= $signed(adc_data_i);
207	                    fwd_buf_q[fwd_in_count] <= $signed(adc_data_q);
208	                    ref_buf_i[fwd_in_count] <= $signed(long_chirp_real);
209	                    ref_buf_q[fwd_in_count] <= $signed(long_chirp_imag);
210	                    fwd_in_count <= fwd_in_count + 1;
211	                end
212	
213	                if (fwd_in_count == FFT_SIZE) begin
214	                    fwd_frame_done <= 1;
215	
216	                    // Bit-reverse copy SIGNAL into work arrays (via <=)
217	                    for (i = 0; i < FFT_SIZE; i = i + 1) begin
218	                        work_re[bit_reverse(i[ADDR_BITS-1:0])] <= {{16{fwd_buf_i[i][15]}}, fwd_buf_i[i]};
219	                        work_im[bit_reverse(i[ADDR_BITS-1:0])] <= {{16{fwd_buf_q[i][15]}}, fwd_buf_q[i]};
220	                    end
221	                end
222	            end else begin
223	                // Bit-reverse copy settled on previous clock.
224	                // Now transition to butterfly computation.
225	                state <= ST_FWD_BUTTERFLY;
226	            end
227	        end
228	
229	        // ================================================================
230	        // FWD_BUTTERFLY: Forward FFT of signal (all stages, simulation only)
231	        // ================================================================
232	        ST_FWD_BUTTERFLY: begin
233	            // In-place radix-2 DIT butterflies (blocking assignments)
234	            for (fft_stage = 0; fft_stage < ADDR_BITS; fft_stage = fft_stage + 1) begin
235	                fft_half = 1 << fft_stage;
236	                fft_span = fft_half << 1;
237	                for (fft_k = 0; fft_k < FFT_SIZE; fft_k = fft_k + fft_span) begin
238	                    for (fft_j = 0; fft_j < fft_half; fft_j = fft_j + 1) begin
239	                        fft_idx_even = fft_k + fft_j;
240	                        fft_idx_odd  = fft_idx_even + fft_half;
241	
242	                        tw_angle = -2.0 * 3.14159265358979 * fft_j / (fft_span * 1.0);
243	                        tw_re = $rtoi($cos(tw_angle) * 32767.0);
244	                        tw_im = $rtoi($sin(tw_angle) * 32767.0);
245	
246	                        t_re = (work_re[fft_idx_odd] * tw_re - work_im[fft_idx_odd] * tw_im) >>> 15;
247	                        t_im = (work_re[fft_idx_odd] * tw_im + work_im[fft_idx_odd] * tw_re) >>> 15;
248	
249	                        u_re = work_re[fft_idx_even];
250	                        u_im = work_im[fft_idx_even];
251	
252	                        work_re[fft_idx_even] = u_re + t_re;
253	                        work_im[fft_idx_even] = u_im + t_im;
254	                        work_re[fft_idx_odd]  = u_re - t_re;
255	                        work_im[fft_idx_odd]  = u_im - t_im;
256	                    end
257	                end
258	            end
259	
260	            // Copy signal FFT results to fwd_out (saturate to 16-bit)
261	            for (i = 0; i < FFT_SIZE; i = i + 1) begin
262	                if (work_re[i] > 32767)
263	                    fwd_out_i[i] <= 16'sh7FFF;
264	                else if (work_re[i] < -32768)
265	                    fwd_out_i[i] <= 16'sh8000;
266	                else
267	                    fwd_out_i[i] <= work_re[i][15:0];
268	
269	                if (work_im[i] > 32767)
270	                    fwd_out_q[i] <= 16'sh7FFF;
271	                else if (work_im[i] < -32768)
272	                    fwd_out_q[i] <= 16'sh8000;
273	                else
274	                    fwd_out_q[i] <= work_im[i][15:0];
275	            end
276	
277	            fwd_out_valid <= 1;
278	            state <= ST_REF_BITREV;
279	
280	            `ifdef SIMULATION
281	            $display("[MF_CHAIN] Forward FFT complete");
282	            `endif
283	        end
284	
285	        // ================================================================
286	        // REF_BITREV: Bit-reverse copy reference into work arrays
287	        // ================================================================
288	        ST_REF_BITREV: begin
289	            for (i = 0; i < FFT_SIZE; i = i + 1) begin
290	                work_re[bit_reverse(i[ADDR_BITS-1:0])] <= {{16{ref_buf_i[i][15]}}, ref_buf_i[i]};
291	                work_im[bit_reverse(i[ADDR_BITS-1:0])] <= {{16{ref_buf_q[i][15]}}, ref_buf_q[i]};
292	            end
293	            state <= ST_REF_BUTTERFLY;
294	        end
295	
296	        // ================================================================
297	        // REF_BUTTERFLY: Forward FFT of reference (same algorithm as signal)
298	        // ================================================================
299	        ST_REF_BUTTERFLY: begin
300	            for (fft_stage = 0; fft_stage < ADDR_BITS; fft_stage = fft_stage + 1) begin
301	                fft_half = 1 << fft_stage;
302	                fft_span = fft_half << 1;
303	                for (fft_k = 0; fft_k < FFT_SIZE; fft_k = fft_k + fft_span) begin
304	                    for (fft_j = 0; fft_j < fft_half; fft_j = fft_j + 1) begin
305	                        fft_idx_even = fft_k + fft_j;
306	                        fft_idx_odd  = fft_idx_even + fft_half;
307	
308	                        tw_angle = -2.0 * 3.14159265358979 * fft_j / (fft_span * 1.0);
309	                        tw_re = $rtoi($cos(tw_angle) * 32767.0);
310	                        tw_im = $rtoi($sin(tw_angle) * 32767.0);
311	
312	                        t_re = (work_re[fft_idx_odd] * tw_re - work_im[fft_idx_odd] * tw_im) >>> 15;
313	                        t_im = (work_re[fft_idx_odd] * tw_im + work_im[fft_idx_odd] * tw_re) >>> 15;
314	
315	                        u_re = work_re[fft_idx_even];
316	                        u_im = work_im[fft_idx_even];
317	
318	                        work_re[fft_idx_even] = u_re + t_re;
319	                        work_im[fft_idx_even] = u_im + t_im;
320	                        work_re[fft_idx_odd]  = u_re - t_re;
321	                        work_im[fft_idx_odd]  = u_im - t_im;
322	                    end
323	                end
324	            end
325	
326	            // Copy reference FFT results to ref_fft (saturate to 16-bit)
327	            for (i = 0; i < FFT_SIZE; i = i + 1) begin
328	                if (work_re[i] > 32767)
329	                    ref_fft_i[i] <= 16'sh7FFF;
330	                else if (work_re[i] < -32768)
331	                    ref_fft_i[i] <= 16'sh8000;
332	                else
333	                    ref_fft_i[i] <= work_re[i][15:0];
334	
335	                if (work_im[i] > 32767)
336	                    ref_fft_q[i] <= 16'sh7FFF;
337	                else if (work_im[i] < -32768)
338	                    ref_fft_q[i] <= 16'sh8000;
339	                else
340	                    ref_fft_q[i] <= work_im[i][15:0];
341	            end
342	
343	            state <= ST_MULTIPLY;
344	
345	            `ifdef SIMULATION
346	            $display("[MF_CHAIN] Reference FFT complete");
347	            `endif
348	        end
349	
350	        // ================================================================
351	        // MULTIPLY: Conjugate multiply FFT(signal) x conj(FFT(reference))
352	        // (a+jb)(c-jd) = (ac+bd) + j(bc-ad)
353	        // Uses fwd_out (signal FFT) and ref_fft (reference FFT)
354	        // ================================================================
355	        ST_MULTIPLY: begin
356	            for (i = 0; i < FFT_SIZE; i = i + 1) begin : mult_loop
357	                reg signed [31:0] a, b, c, d;
358	                reg signed [31:0] ac, bd, bc, ad;
359	                reg signed [31:0] re_result, im_result;
360	                
361	                a = {{16{fwd_out_i[i][15]}}, fwd_out_i[i]};
362	                b = {{16{fwd_out_q[i][15]}}, fwd_out_q[i]};
363	                c = {{16{ref_fft_i[i][15]}}, ref_fft_i[i]};
364	                d = {{16{ref_fft_q[i][15]}}, ref_fft_q[i]};
365	
366	                ac = (a * c) >>> 15;
367	                bd = (b * d) >>> 15;
368	                bc = (b * c) >>> 15;
369	                ad = (a * d) >>> 15;
370	
371	                re_result = ac + bd;
372	                im_result = bc - ad;
373	
374	                // Saturate
375	                if (re_result > 32767)
376	                    mult_out_i[i] <= 16'sh7FFF;
377	                else if (re_result < -32768)
378	                    mult_out_i[i] <= 16'sh8000;
379	                else
380	                    mult_out_i[i] <= re_result[15:0];
381	
382	                if (im_result > 32767)
383	                    mult_out_q[i] <= 16'sh7FFF;
384	                else if (im_result < -32768)
385	                    mult_out_q[i] <= 16'sh8000;
386	                else
387	                    mult_out_q[i] <= im_result[15:0];
388	            end
389	
390	            mult_done <= 1;
391	            state     <= ST_INV_BITREV;
392	
393	            `ifdef SIMULATION
394	            $display("[MF_CHAIN] Conjugate multiply complete");
395	            `endif
396	        end
397	
398	        // ================================================================
399	        // INV_BITREV: Bit-reverse copy conjugate-multiply product
400	        // ================================================================
401	        ST_INV_BITREV: begin
402	            for (i = 0; i < FFT_SIZE; i = i + 1) begin
403	                work_re[bit_reverse(i[ADDR_BITS-1:0])] <= {{16{mult_out_i[i][15]}}, mult_out_i[i]};
404	                work_im[bit_reverse(i[ADDR_BITS-1:0])] <= {{16{mult_out_q[i][15]}}, mult_out_q[i]};
405	            end
406	            state <= ST_INV_BUTTERFLY;
407	        end
408	
409	        // ================================================================
410	        // INV_BUTTERFLY: IFFT butterflies (positive twiddle) + 1/N scaling
411	        // ================================================================
412	        ST_INV_BUTTERFLY: begin
413	            for (fft_stage = 0; fft_stage < ADDR_BITS; fft_stage = fft_stage + 1) begin
414	                fft_half = 1 << fft_stage;
415	                fft_span = fft_half << 1;
416	                for (fft_k = 0; fft_k < FFT_SIZE; fft_k = fft_k + fft_span) begin
417	                    for (fft_j = 0; fft_j < fft_half; fft_j = fft_j + 1) begin
418	                        fft_idx_even = fft_k + fft_j;
419	                        fft_idx_odd  = fft_idx_even + fft_half;
420	
421	                        // IFFT twiddle: +2*pi (positive exponent for inverse)
422	                        tw_angle = +2.0 * 3.14159265358979 * fft_j / (fft_span * 1.0);
423	                        tw_re = $rtoi($cos(tw_angle) * 32767.0);
424	                        tw_im = $rtoi($sin(tw_angle) * 32767.0);
425	
426	                        t_re = (work_re[fft_idx_odd] * tw_re - work_im[fft_idx_odd] * tw_im) >>> 15;
427	                        t_im = (work_re[fft_idx_odd] * tw_im + work_im[fft_idx_odd] * tw_re) >>> 15;
428	
429	                        u_re = work_re[fft_idx_even];
430	                        u_im = work_im[fft_idx_even];
431	
432	                        work_re[fft_idx_even] = u_re + t_re;
433	                        work_im[fft_idx_even] = u_im + t_im;
434	                        work_re[fft_idx_odd]  = u_re - t_re;
435	                        work_im[fft_idx_odd]  = u_im - t_im;
436	                    end
437	                end
438	            end
439	
440	            // Scale by 1/N (right shift by log2(1024) = 10) and store
441	            for (i = 0; i < FFT_SIZE; i = i + 1) begin : ifft_scale
442	                reg signed [31:0] scaled_re, scaled_im;
443	                scaled_re = work_re[i] >>> ADDR_BITS;
444	                scaled_im = work_im[i] >>> ADDR_BITS;
445	
446	                if (scaled_re > 32767)
447	                    ifft_out_i[i] <= 16'sh7FFF;
448	                else if (scaled_re < -32768)
449	                    ifft_out_i[i] <= 16'sh8000;
450	                else
451	                    ifft_out_i[i] <= scaled_re[15:0];
452	
453	                if (scaled_im > 32767)
454	                    ifft_out_q[i] <= 16'sh7FFF;
455	                else if (scaled_im < -32768)
456	                    ifft_out_q[i] <= 16'sh8000;
457	                else
458	                    ifft_out_q[i] <= scaled_im[15:0];
459	            end
460	
461	            ifft_done <= 1;
462	            state     <= ST_OUTPUT;
463	
464	            `ifdef SIMULATION
465	            $display("[MF_CHAIN] Inverse FFT complete — range profile ready");
466	            `endif
467	        end
468	
469	        // ================================================================
470	        // OUTPUT: Stream out 1024 range profile samples, one per clock
471	        // ================================================================
472	        ST_OUTPUT: begin
473	            if (out_count < FFT_SIZE) begin
474	                out_i_reg     <= ifft_out_i[out_count];
475	                out_q_reg     <= ifft_out_q[out_count];
476	                out_valid_reg <= 1'b1;
477	                out_count     <= out_count + 1;
478	            end else begin
479	                state <= ST_DONE;
480	            end
481	        end
482	
483	        // ================================================================
484	        // DONE: Return to idle, ready for next frame
485	        // ================================================================
486	        ST_DONE: begin
487	            state <= ST_IDLE;
488	
489	            `ifdef SIMULATION
490	            $display("[MF_CHAIN] Frame complete, returning to IDLE");
491	            `endif
492	        end
493	
494	        default: state <= ST_IDLE;
495	        endcase
496	    end
497	end
498	
499	// ============================================================================
500	// OUTPUT ASSIGNMENTS
501	// ============================================================================
502	assign range_profile_i     = out_i_reg;
503	assign range_profile_q     = out_q_reg;
504	assign range_profile_valid = out_valid_reg;
505	assign chain_state         = state;
506	
507	// ============================================================================
508	// BUFFER INITIALIZATION (simulation)
509	// ============================================================================
510	integer init_idx;
511	initial begin
512	    for (init_idx = 0; init_idx < FFT_SIZE; init_idx = init_idx + 1) begin
513	        fwd_buf_i[init_idx]  = 16'd0;
514	        fwd_buf_q[init_idx]  = 16'd0;
515	        fwd_out_i[init_idx]  = 16'd0;
516	        fwd_out_q[init_idx]  = 16'd0;
517	        ref_buf_i[init_idx]  = 16'd0;
518	        ref_buf_q[init_idx]  = 16'd0;
519	        ref_fft_i[init_idx]  = 16'd0;
520	        ref_fft_q[init_idx]  = 16'd0;
521	        mult_out_i[init_idx] = 16'd0;
522	        mult_out_q[init_idx] = 16'd0;
523	        ifft_out_i[init_idx] = 16'd0;
524	        ifft_out_q[init_idx] = 16'd0;
525	        work_re[init_idx]    = 32'd0;
526	        work_im[init_idx]    = 32'd0;
527	    end
528	end
529	
530	`else
531	// ============================================================================
532	// SYNTHESIS IMPLEMENTATION — Radix-2 DIT FFT via fft_engine
533	// ============================================================================
534	// Uses a single fft_engine instance (1024-pt) reused 3 times:
535	//   1. Forward FFT of signal
536	//   2. Forward FFT of reference
537	//   3. Inverse FFT of conjugate product
538	// Conjugate multiply done via frequency_matched_filter (4-stage pipeline).
539	//
540	// Buffer scheme (BRAM-inferrable):
541	//   sig_buf[1024]:  ADC input -> signal FFT output
542	//   ref_buf[1024]:  Reference input -> reference FFT output
543	//   prod_buf[1024]: Conjugate multiply output -> IFFT output
544	//
545	// Memory access is INSIDE always @(posedge clk) blocks (no async reset)
546	// using local blocking variables. This eliminates NBA race conditions
547	// and enables Vivado BRAM inference (same pattern as fft_engine.v).
548	//
549	// BRAM read latency (1 cycle) is handled by "primed" flags:
550	//   feed_primed  — for FFT feed operations
551	//   mult_primed  — for conjugate multiply feed
552	//   out_primed   — for output streaming
553	// ============================================================================
554	
555	localparam FFT_SIZE  = 1024;
556	localparam ADDR_BITS = 10;
557	
558	// State encoding
559	localparam [3:0] ST_IDLE     = 4'd0,
560	                 ST_COLLECT  = 4'd1,   // Collect 1024 ADC + ref samples
561	                 ST_SIG_FFT  = 4'd2,   // Forward FFT of signal
562	                 ST_SIG_CAP  = 4'd3,   // Capture signal FFT output
563	                 ST_REF_FFT  = 4'd4,   // Forward FFT of reference
564	                 ST_REF_CAP  = 4'd5,   // Capture reference FFT output
565	                 ST_MULTIPLY = 4'd6,   // Conjugate multiply (pipelined)
566	                 ST_INV_FFT  = 4'd7,   // Inverse FFT of product
567	                 ST_INV_CAP  = 4'd8,   // Capture IFFT output
568	                 ST_OUTPUT   = 4'd9,   // Stream 1024 results
569	                 ST_DONE     = 4'd10;
570	
571	reg [3:0] state;
572	
573	// ============================================================================
574	// DATA BUFFERS (block RAM) — declared here, accessed in BRAM port blocks
575	// ============================================================================
576	(* ram_style = "block" *) reg signed [15:0] sig_buf_i [0:FFT_SIZE-1];
577	(* ram_style = "block" *) reg signed [15:0] sig_buf_q [0:FFT_SIZE-1];
578	(* ram_style = "block" *) reg signed [15:0] ref_buf_i [0:FFT_SIZE-1];
579	(* ram_style = "block" *) reg signed [15:0] ref_buf_q [0:FFT_SIZE-1];
580	(* ram_style = "block" *) reg signed [15:0] prod_buf_i [0:FFT_SIZE-1];
581	(* ram_style = "block" *) reg signed [15:0] prod_buf_q [0:FFT_SIZE-1];
582	
583	// BRAM read data (registered outputs from port blocks)
584	reg signed [15:0] sig_rdata_i, sig_rdata_q;
585	reg signed [15:0] ref_rdata_i, ref_rdata_q;
586	reg signed [15:0] prod_rdata_i, prod_rdata_q;
587	
588	// ============================================================================
589	// COUNTERS
590	// ============================================================================
591	reg [ADDR_BITS:0] collect_count;   // 0..1024 for sample collection
592	reg [ADDR_BITS:0] feed_count;      // 0..1024 for feeding FFT engine
593	reg [ADDR_BITS:0] cap_count;       // 0..1024 for capturing FFT output
594	reg [ADDR_BITS:0] mult_count;      // 0..1024 for multiply feeding
595	reg [ADDR_BITS:0] out_count;       // 0..1024 for output streaming
596	
597	// BRAM read latency pipeline flags
598	reg feed_primed;   // 1 = BRAM rdata valid for feed operations
599	reg mult_primed;   // 1 = BRAM rdata valid for multiply reads
600	reg out_primed;    // 1 = BRAM rdata valid for output reads
601	
602	// ============================================================================
603	// FFT ENGINE INTERFACE (single instance, reused 3 times)
604	// ============================================================================
605	reg fft_start;
606	reg fft_inverse;
607	reg signed [15:0] fft_din_re, fft_din_im;
608	reg fft_din_valid;
609	wire signed [15:0] fft_dout_re, fft_dout_im;
610	wire fft_dout_valid;
611	wire fft_busy;
612	wire fft_done;
613	
614	fft_engine #(
615	    .N(FFT_SIZE),
616	    .LOG2N(ADDR_BITS),
617	    .DATA_W(16),
618	    .INTERNAL_W(32),
619	    .TWIDDLE_W(16),
620	    .TWIDDLE_FILE("fft_twiddle_1024.mem")
621	) fft_inst (
622	    .clk(clk),
623	    .reset_n(reset_n),
624	    .start(fft_start),
625	    .inverse(fft_inverse),
626	    .din_re(fft_din_re),
627	    .din_im(fft_din_im),
628	    .din_valid(fft_din_valid),
629	    .dout_re(fft_dout_re),
630	    .dout_im(fft_dout_im),
631	    .dout_valid(fft_dout_valid),
632	    .busy(fft_busy),
633	    .done(fft_done)
634	);
635	
636	// ============================================================================
637	// CONJUGATE MULTIPLY INTERFACE (frequency_matched_filter)
638	// ============================================================================
639	reg signed [15:0] mf_sig_re, mf_sig_im;
640	reg signed [15:0] mf_ref_re, mf_ref_im;
641	reg mf_valid_in;
642	wire signed [15:0] mf_out_re, mf_out_im;
643	wire mf_valid_out;
644	
645	frequency_matched_filter mf_inst (
646	    .clk(clk),
647	    .reset_n(reset_n),
648	    .fft_real_in(mf_sig_re),
649	    .fft_imag_in(mf_sig_im),
650	    .fft_valid_in(mf_valid_in),
651	    .ref_chirp_real(mf_ref_re),
652	    .ref_chirp_imag(mf_ref_im),
653	    .filtered_real(mf_out_re),
654	    .filtered_imag(mf_out_im),
655	    .filtered_valid(mf_valid_out),
656	    .state()
657	);
658	
659	// Pipeline flush counter for matched filter (4-stage pipeline)
660	reg [2:0] mf_flush_count;
661	
662	// ============================================================================
663	// OUTPUT REGISTERS
664	// ============================================================================
665	reg out_valid_reg;
666	reg signed [15:0] out_i_reg, out_q_reg;
667	
668	// ============================================================================
669	// BRAM PORT: sig_buf — all address/we/wdata computed inline (race-free)
670	// ============================================================================
671	// Handles: IDLE/COLLECT writes, SIG_FFT/SIG_CAP capture writes,
672	//          SIG_FFT feed reads, MULTIPLY signal reads
673	// No async reset in sensitivity list — enables Vivado BRAM inference.
674	// ============================================================================
675	always @(posedge clk) begin : sig_bram_port
676	    reg                    we;
677	    reg  [ADDR_BITS-1:0]   addr;
678	    reg  signed [15:0]     wdata_i, wdata_q;
679	
680	    // Defaults
681	    we      = 1'b0;
682	    addr    = 0;
683	    wdata_i = 0;
684	    wdata_q = 0;
685	
686	    case (state)
687	    ST_IDLE: begin
688	        if (adc_valid) begin
689	            we      = 1'b1;
690	            addr    = 0;
691	            wdata_i = $signed(adc_data_i);
692	            wdata_q = $signed(adc_data_q);
693	        end
694	    end
695	    ST_COLLECT: begin
696	        if (adc_valid && collect_count < FFT_SIZE) begin
697	            we      = 1'b1;
698	            addr    = collect_count[ADDR_BITS-1:0];
699	            wdata_i = $signed(adc_data_i);
700	            wdata_q = $signed(adc_data_q);
701	        end
702	    end
703	    ST_SIG_FFT: begin
704	        if (feed_count < FFT_SIZE && !feed_primed) begin
705	            // Pre-read cycle: present address, no write
706	            addr = feed_count[ADDR_BITS-1:0];
707	        end else if (feed_count <= FFT_SIZE && feed_primed) begin
708	            // Primed: read address for NEXT sample (or hold last)
709	            if (feed_count < FFT_SIZE)
710	                addr = feed_count[ADDR_BITS-1:0];
711	            else
712	                addr = 0; // don't care, past last sample
713	        end
714	        // Capture FFT output (write) — happens after feeding is done
715	        if (fft_dout_valid && cap_count < FFT_SIZE) begin
716	            we      = 1'b1;
717	            addr    = cap_count[ADDR_BITS-1:0];
718	            wdata_i = fft_dout_re;
719	            wdata_q = fft_dout_im;
720	        end
721	    end
722	    ST_SIG_CAP: begin
723	        if (fft_dout_valid && cap_count < FFT_SIZE) begin
724	            we      = 1'b1;
725	            addr    = cap_count[ADDR_BITS-1:0];
726	            wdata_i = fft_dout_re;
727	            wdata_q = fft_dout_im;
728	        end
729	    end
730	    ST_MULTIPLY: begin
731	        // Read signal FFT results for conjugate multiply
732	        if (mult_count < FFT_SIZE && !mult_primed) begin
733	            addr = mult_count[ADDR_BITS-1:0];
734	        end else if (mult_count <= FFT_SIZE && mult_primed) begin
735	            if (mult_count < FFT_SIZE)
736	                addr = mult_count[ADDR_BITS-1:0];
737	            else
738	                addr = 0;
739	        end
740	    end
741	    default: begin
742	        // keep defaults
743	    end
744	    endcase
745	
746	    // BRAM write
747	    if (we) begin
748	        sig_buf_i[addr] <= wdata_i;
749	        sig_buf_q[addr] <= wdata_q;
750	    end
751	    // BRAM read (1-cycle latency)
752	    sig_rdata_i <= sig_buf_i[addr];
753	    sig_rdata_q <= sig_buf_q[addr];
754	end
755	
756	// ============================================================================
757	// BRAM PORT: ref_buf — all address/we/wdata computed inline (race-free)
758	// ============================================================================
759	// Handles: IDLE/COLLECT writes, REF_FFT/REF_CAP capture writes,
760	//          REF_FFT feed reads, MULTIPLY reference reads
761	// ============================================================================
762	always @(posedge clk) begin : ref_bram_port
763	    reg                    we;
764	    reg  [ADDR_BITS-1:0]   addr;
765	    reg  signed [15:0]     wdata_i, wdata_q;
766	
767	    // Defaults
768	    we      = 1'b0;
769	    addr    = 0;
770	    wdata_i = 0;
771	    wdata_q = 0;
772	
773	    case (state)
774	    ST_IDLE: begin
775	        if (adc_valid) begin
776	            we      = 1'b1;
777	            addr    = 0;
778	            wdata_i = $signed(long_chirp_real);
779	            wdata_q = $signed(long_chirp_imag);
780	        end
781	    end
782	    ST_COLLECT: begin
783	        if (adc_valid && collect_count < FFT_SIZE) begin
784	            we      = 1'b1;
785	            addr    = collect_count[ADDR_BITS-1:0];
786	            wdata_i = $signed(long_chirp_real);
787	            wdata_q = $signed(long_chirp_imag);
788	        end
789	    end
790	    ST_REF_FFT: begin
791	        if (feed_count < FFT_SIZE && !feed_primed) begin
792	            addr = feed_count[ADDR_BITS-1:0];
793	        end else if (feed_count <= FFT_SIZE && feed_primed) begin
794	            if (feed_count < FFT_SIZE)
795	                addr = feed_count[ADDR_BITS-1:0];
796	            else
797	                addr = 0;
798	        end
799	        // Capture FFT output
800	        if (fft_dout_valid && cap_count < FFT_SIZE) begin
801	            we      = 1'b1;
802	            addr    = cap_count[ADDR_BITS-1:0];
803	            wdata_i = fft_dout_re;
804	            wdata_q = fft_dout_im;
805	        end
806	    end
807	    ST_REF_CAP: begin
808	        if (fft_dout_valid && cap_count < FFT_SIZE) begin
809	            we      = 1'b1;
810	            addr    = cap_count[ADDR_BITS-1:0];
811	            wdata_i = fft_dout_re;
812	            wdata_q = fft_dout_im;
813	        end
814	    end
815	    ST_MULTIPLY: begin
816	        // Read reference FFT results for conjugate multiply
817	        if (mult_count < FFT_SIZE && !mult_primed) begin
818	            addr = mult_count[ADDR_BITS-1:0];
819	        end else if (mult_count <= FFT_SIZE && mult_primed) begin
820	            if (mult_count < FFT_SIZE)
821	                addr = mult_count[ADDR_BITS-1:0];
822	            else
823	                addr = 0;
824	        end
825	    end
826	    default: begin
827	        // keep defaults
828	    end
829	    endcase
830	
831	    // BRAM write
832	    if (we) begin
833	        ref_buf_i[addr] <= wdata_i;
834	        ref_buf_q[addr] <= wdata_q;
835	    end
836	    // BRAM read (1-cycle latency)
837	    ref_rdata_i <= ref_buf_i[addr];
838	    ref_rdata_q <= ref_buf_q[addr];
839	end
840	
841	// ============================================================================
842	// BRAM PORT: prod_buf — all address/we/wdata computed inline (race-free)
843	// ============================================================================
844	// Handles: MULTIPLY capture writes, INV_FFT/INV_CAP capture writes,
845	//          INV_FFT feed reads, OUTPUT reads
846	// ============================================================================
847	always @(posedge clk) begin : prod_bram_port
848	    reg                    we;
849	    reg  [ADDR_BITS-1:0]   addr;
850	    reg  signed [15:0]     wdata_i, wdata_q;
851	
852	    // Defaults
853	    we      = 1'b0;
854	    addr    = 0;
855	    wdata_i = 0;
856	    wdata_q = 0;
857	
858	    case (state)
859	    ST_MULTIPLY: begin
860	        // Capture conjugate multiply output
861	        if (mf_valid_out && cap_count < FFT_SIZE) begin
862	            we      = 1'b1;
863	            addr    = cap_count[ADDR_BITS-1:0];
864	            wdata_i = mf_out_re;
865	            wdata_q = mf_out_im;
866	        end
867	    end
868	    ST_INV_FFT: begin
869	        if (feed_count < FFT_SIZE && !feed_primed) begin
870	            addr = feed_count[ADDR_BITS-1:0];
871	        end else if (feed_count <= FFT_SIZE && feed_primed) begin
872	            if (feed_count < FFT_SIZE)
873	                addr = feed_count[ADDR_BITS-1:0];
874	            else
875	                addr = 0;
876	        end
877	        // Capture IFFT output
878	        if (fft_dout_valid && cap_count < FFT_SIZE) begin
879	            we      = 1'b1;
880	            addr    = cap_count[ADDR_BITS-1:0];
881	            wdata_i = fft_dout_re;
882	            wdata_q = fft_dout_im;
883	        end
884	    end
885	    ST_INV_CAP: begin
886	        if (fft_dout_valid && cap_count < FFT_SIZE) begin
887	            we      = 1'b1;
888	            addr    = cap_count[ADDR_BITS-1:0];
889	            wdata_i = fft_dout_re;
890	            wdata_q = fft_dout_im;
891	        end
892	    end
893	    ST_OUTPUT: begin
894	        // Read product buffer for output streaming
895	        if (out_count < FFT_SIZE && !out_primed) begin
896	            addr = out_count[ADDR_BITS-1:0];
897	        end else if (out_count <= FFT_SIZE && out_primed) begin
898	            if (out_count < FFT_SIZE)
899	                addr = out_count[ADDR_BITS-1:0];
900	            else
901	                addr = 0;
902	        end
903	    end
904	    default: begin
905	        // keep defaults
906	    end
907	    endcase
908	
909	    // BRAM write
910	    if (we) begin
911	        prod_buf_i[addr] <= wdata_i;
912	        prod_buf_q[addr] <= wdata_q;
913	    end
914	    // BRAM read (1-cycle latency)
915	    prod_rdata_i <= prod_buf_i[addr];
916	    prod_rdata_q <= prod_buf_q[addr];
917	end
918	
919	// ============================================================================
920	// MAIN FSM — no buffer array accesses here (all via BRAM ports above)
921	// ============================================================================
922	always @(posedge clk or negedge reset_n) begin
923	    if (!reset_n) begin
924	        state          <= ST_IDLE;
925	        collect_count  <= 0;
926	        feed_count     <= 0;
927	        cap_count      <= 0;
928	        mult_count     <= 0;
929	        out_count      <= 0;
930	        feed_primed    <= 1'b0;
931	        mult_primed    <= 1'b0;
932	        out_primed     <= 1'b0;
933	        fft_start      <= 1'b0;
934	        fft_inverse    <= 1'b0;
935	        fft_din_re     <= 0;
936	        fft_din_im     <= 0;
937	        fft_din_valid  <= 1'b0;
938	        mf_sig_re      <= 0;
939	        mf_sig_im      <= 0;
940	        mf_ref_re      <= 0;
941	        mf_ref_im      <= 0;
942	        mf_valid_in    <= 1'b0;
943	        mf_flush_count <= 0;
944	        out_valid_reg  <= 1'b0;
945	        out_i_reg      <= 0;
946	        out_q_reg      <= 0;
947	    end else begin
948	        // Defaults
949	        fft_start     <= 1'b0;
950	        fft_din_valid <= 1'b0;
951	        mf_valid_in   <= 1'b0;
952	        out_valid_reg <= 1'b0;
953	
954	        case (state)
955	
956	        // ================================================================
957	        ST_IDLE: begin
958	            collect_count <= 0;
959	            feed_primed   <= 1'b0;
960	            mult_primed   <= 1'b0;
961	            out_primed    <= 1'b0;
962	            if (adc_valid) begin
963	                // First sample written by sig/ref BRAM ports (they see
964	                // state==ST_IDLE && adc_valid)
965	                collect_count <= 1;
966	                state <= ST_COLLECT;
967	            end
968	        end
969	
970	        // ================================================================
971	        // COLLECT: Gather 1024 ADC + reference samples
972	        // Writes happen in sig/ref BRAM ports (they see state==ST_COLLECT)
973	        // ================================================================
974	        ST_COLLECT: begin
975	            if (adc_valid && collect_count < FFT_SIZE) begin
976	                collect_count <= collect_count + 1;
977	            end
978	
979	            if (collect_count == FFT_SIZE) begin
980	                // All 1024 samples collected — start signal FFT
981	                state       <= ST_SIG_FFT;
982	                fft_start   <= 1'b1;
983	                fft_inverse <= 1'b0;  // Forward FFT
984	                feed_count  <= 0;
985	                cap_count   <= 0;
986	                feed_primed <= 1'b0;
987	            end
988	        end
989	
990	        // ================================================================
991	        // SIG_FFT: Feed signal buffer to FFT engine (forward)
992	        // BRAM read has 1-cycle latency: address presented in BRAM port,
993	        // data available in sig_rdata_i/q next cycle.
994	        // ================================================================
995	        ST_SIG_FFT: begin
996	            // Feed phase: read sig_buf -> fft_din
997	            if (feed_count < FFT_SIZE) begin
998	                if (!feed_primed) begin
999	                    // Pre-read cycle: address presented to BRAM, wait 1 cycle
1000	                    feed_primed <= 1'b1;
1001	                    feed_count  <= feed_count + 1;
1002	                    // fft_din_valid stays 0 (default)
1003	                end else begin
1004	                    // Primed: BRAM rdata is valid for previous address
1005	                    fft_din_re    <= sig_rdata_i;
1006	                    fft_din_im    <= sig_rdata_q;
1007	                    fft_din_valid <= 1'b1;
1008	                    feed_count    <= feed_count + 1;
1009	                end
1010	            end else if (feed_count == FFT_SIZE && feed_primed) begin
1011	                // Last sample: BRAM rdata has data for address 1023
1012	                fft_din_re    <= sig_rdata_i;
1013	                fft_din_im    <= sig_rdata_q;
1014	                fft_din_valid <= 1'b1;
1015	                feed_count    <= feed_count + 1; // -> 1025, stops feeding
1016	            end
1017	
1018	            // Capture FFT output (writes happen in BRAM port)
1019	            if (fft_dout_valid && cap_count < FFT_SIZE) begin
1020	                cap_count <= cap_count + 1;
1021	            end
1022	
1023	            if (fft_done) begin
1024	                state <= ST_SIG_CAP;
1025	            end
1026	        end
1027	
1028	        // ================================================================
1029	        // SIG_CAP: Ensure all signal FFT outputs captured
1030	        // ================================================================
1031	        ST_SIG_CAP: begin
1032	            if (fft_dout_valid && cap_count < FFT_SIZE) begin
1033	                cap_count <= cap_count + 1;
1034	            end
1035	
1036	            // Start reference FFT
1037	            state       <= ST_REF_FFT;
1038	            fft_start   <= 1'b1;
1039	            fft_inverse <= 1'b0;  // Forward FFT
1040	            feed_count  <= 0;
1041	            cap_count   <= 0;
1042	            feed_primed <= 1'b0;
1043	        end
1044	
1045	        // ================================================================
1046	        // REF_FFT: Feed reference buffer to FFT engine (forward)
1047	        // ================================================================
1048	        ST_REF_FFT: begin
1049	            // Feed phase: read ref_buf -> fft_din
1050	            if (feed_count < FFT_SIZE) begin
1051	                if (!feed_primed) begin
1052	                    feed_primed <= 1'b1;
1053	                    feed_count  <= feed_count + 1;
1054	                end else begin
1055	                    fft_din_re    <= ref_rdata_i;
1056	                    fft_din_im    <= ref_rdata_q;
1057	                    fft_din_valid <= 1'b1;
1058	                    feed_count    <= feed_count + 1;
1059	                end
1060	            end else if (feed_count == FFT_SIZE && feed_primed) begin
1061	                fft_din_re    <= ref_rdata_i;
1062	                fft_din_im    <= ref_rdata_q;
1063	                fft_din_valid <= 1'b1;
1064	                feed_count    <= feed_count + 1;
1065	            end
1066	
1067	            if (fft_dout_valid && cap_count < FFT_SIZE) begin
1068	                cap_count <= cap_count + 1;
1069	            end
1070	
1071	            if (fft_done) begin
1072	                state <= ST_REF_CAP;
1073	            end
1074	        end
1075	
1076	        // ================================================================
1077	        // REF_CAP: Ensure all ref FFT outputs captured
1078	        // ================================================================
1079	        ST_REF_CAP: begin
1080	            if (fft_dout_valid && cap_count < FFT_SIZE) begin
1081	                cap_count <= cap_count + 1;
1082	            end
1083	
1084	            state          <= ST_MULTIPLY;
1085	            mult_count     <= 0;
1086	            cap_count      <= 0;
1087	            mf_flush_count <= 0;
1088	            mult_primed    <= 1'b0;
1089	        end
1090	
1091	        // ================================================================
1092	        // MULTIPLY: Stream sig FFT and ref FFT through freq_matched_filter
1093	        // Both sig_buf and ref_buf are read simultaneously (separate BRAM
1094	        // ports). Pipeline latency = 4 clocks. Feed 1024 pairs, then flush.
1095	        // ================================================================
1096	        ST_MULTIPLY: begin
1097	            if (mult_count < FFT_SIZE) begin
1098	                if (!mult_primed) begin
1099	                    // Pre-read cycle
1100	                    mult_primed <= 1'b1;
1101	                    mult_count  <= mult_count + 1;
1102	                end else begin
1103	                    mf_sig_re   <= sig_rdata_i;
1104	                    mf_sig_im   <= sig_rdata_q;
1105	                    mf_ref_re   <= ref_rdata_i;
1106	                    mf_ref_im   <= ref_rdata_q;
1107	                    mf_valid_in <= 1'b1;
1108	                    mult_count  <= mult_count + 1;
1109	                end
1110	            end else if (mult_count == FFT_SIZE && mult_primed) begin
1111	                // Last sample
1112	                mf_sig_re   <= sig_rdata_i;
1113	                mf_sig_im   <= sig_rdata_q;
1114	                mf_ref_re   <= ref_rdata_i;
1115	                mf_ref_im   <= ref_rdata_q;
1116	                mf_valid_in <= 1'b1;
1117	                mult_count  <= mult_count + 1;
1118	            end else begin
1119	                // Pipeline flush — wait for remaining outputs
1120	                mf_flush_count <= mf_flush_count + 1;
1121	            end
1122	
1123	            // Capture multiply outputs (writes happen in BRAM port)
1124	            if (mf_valid_out && cap_count < FFT_SIZE) begin
1125	                cap_count <= cap_count + 1;
1126	            end
1127	
1128	            // Done when all outputs captured
1129	            if (cap_count == FFT_SIZE) begin
1130	                state       <= ST_INV_FFT;
1131	                fft_start   <= 1'b1;
1132	                fft_inverse <= 1'b1;  // Inverse FFT
1133	                feed_count  <= 0;
1134	                cap_count   <= 0;
1135	                feed_primed <= 1'b0;
1136	            end
1137	        end
1138	
1139	        // ================================================================
1140	        // INV_FFT: Feed product buffer to FFT engine (inverse)
1141	        // ================================================================
1142	        ST_INV_FFT: begin
1143	            if (feed_count < FFT_SIZE) begin
1144	                if (!feed_primed) begin
1145	                    feed_primed <= 1'b1;
1146	                    feed_count  <= feed_count + 1;
1147	                end else begin
1148	                    fft_din_re    <= prod_rdata_i;
1149	                    fft_din_im    <= prod_rdata_q;
1150	                    fft_din_valid <= 1'b1;
1151	                    feed_count    <= feed_count + 1;
1152	                end
1153	            end else if (feed_count == FFT_SIZE && feed_primed) begin
1154	                fft_din_re    <= prod_rdata_i;
1155	                fft_din_im    <= prod_rdata_q;
1156	                fft_din_valid <= 1'b1;
1157	                feed_count    <= feed_count + 1;
1158	            end
1159	
1160	            if (fft_dout_valid && cap_count < FFT_SIZE) begin
1161	                cap_count <= cap_count + 1;
1162	            end
1163	
1164	            if (fft_done) begin
1165	                state <= ST_INV_CAP;
1166	            end
1167	        end
1168	
1169	        // ================================================================
1170	        // INV_CAP: Ensure all IFFT outputs captured
1171	        // ================================================================
1172	        ST_INV_CAP: begin
1173	            if (fft_dout_valid && cap_count < FFT_SIZE) begin
1174	                cap_count <= cap_count + 1;
1175	            end
1176	
1177	            state      <= ST_OUTPUT;
1178	            out_count  <= 0;
1179	            out_primed <= 1'b0;
1180	        end
1181	
1182	        // ================================================================
1183	        // OUTPUT: Stream 1024 range profile samples
1184	        // BRAM read latency: present address, data valid next cycle.
1185	        // ================================================================
1186	        ST_OUTPUT: begin
1187	            if (out_count < FFT_SIZE) begin
1188	                if (!out_primed) begin
1189	                    // Pre-read cycle
1190	                    out_primed <= 1'b1;
1191	                    out_count  <= out_count + 1;
1192	                end else begin
1193	                    out_i_reg     <= prod_rdata_i;
1194	                    out_q_reg     <= prod_rdata_q;
1195	                    out_valid_reg <= 1'b1;
1196	                    out_count     <= out_count + 1;
1197	                end
1198	            end else if (out_count == FFT_SIZE && out_primed) begin
1199	                // Last sample
1200	                out_i_reg     <= prod_rdata_i;
1201	                out_q_reg     <= prod_rdata_q;
1202	                out_valid_reg <= 1'b1;
1203	                out_count     <= out_count + 1;
1204	            end else begin
1205	                state <= ST_DONE;
1206	            end
1207	        end
1208	
1209	        // ================================================================
1210	        // DONE: Return to idle
1211	        // ================================================================
1212	        ST_DONE: begin
1213	            state <= ST_IDLE;
1214	        end
1215	
1216	        default: state <= ST_IDLE;
1217	
1218	        endcase
1219	    end
1220	end
1221	
1222	// ============================================================================
1223	// OUTPUT ASSIGNMENTS
1224	// ============================================================================
1225	assign range_profile_i     = out_i_reg;
1226	assign range_profile_q     = out_q_reg;
1227	assign range_profile_valid = out_valid_reg;
1228	assign chain_state         = state;
1229	
1230	// ============================================================================
1231	// BUFFER INIT (for simulation — Vivado ignores initial blocks on arrays)
1232	// ============================================================================
1233	integer init_idx;
1234	initial begin
1235	    for (init_idx = 0; init_idx < FFT_SIZE; init_idx = init_idx + 1) begin
1236	        sig_buf_i[init_idx]  = 0;
1237	        sig_buf_q[init_idx]  = 0;
1238	        ref_buf_i[init_idx]  = 0;
1239	        ref_buf_q[init_idx]  = 0;
1240	        prod_buf_i[init_idx] = 0;
1241	        prod_buf_q[init_idx] = 0;
1242	    end
1243	end
1244	
1245	`endif
1246	
1247	endmodule
1248

